module alu(
    input [31:0] a, b,
    input [5:0] aluc,
    output reg [31:0] r,
    output reg zero,
    output reg carry,
    output reg negative,
    output reg overflow,
    output reg flag
);

reg [31:0] temp_result;
reg [31:0] temp_a;
reg [31:0] temp_b;

always @* begin
    case (aluc)
        6'b100000: begin 
            temp_result = a + b;
            zero = (temp_result == 32'b0);
            carry = (temp_result < a);
            negative = (temp_result[31] == 1'b1);
            overflow = ((a[31] == b[31]) && (a[31] != temp_result[31]));
            flag = 1'b0;
        end

        6'b100001: begin 
            temp_result = a + b;
            zero = (temp_result == 32'b0);
            carry = (temp_result < a);
            negative = (temp_result[31] == 1'b1);
            overflow = 1'b0;
            flag = 1'b0;
        end

        6'b100010: begin 
            temp_result = a - b;
            zero = (temp_result == 32'b0);
            carry = (temp_result > a);
            negative = (temp_result[31] == 1'b1);
            overflow = ((a[31] != b[31]) && (a[31] != temp_result[31]));
            flag = 1'b0;
        end

        6'b100011: begin 
            temp_result = a - b;
            zero = (temp_result == 32'b0);
            carry = (temp_result > a);
            negative = (temp_result[31] == 1'b1);
            overflow = 1'b0;
            flag = 1'b0;
        end

        6'b100100: begin 
            temp_result = a & b;
            zero = (temp_result == 32'b0);
            carry = 1'b0;
            negative = (temp_result[31] == 1'b1);
            overflow = 1'b0;
            flag = 1'b0;
        end

        6'b100101: begin 
            temp_result = a | b;
            zero = (temp_result == 32'b0);
            carry = 1'b0;
            negative = (temp_result[31] == 1'b1);
            overflow = 1'b0;
            flag = 1'b0;
        end

        6'b100110: begin 
            temp_result = a ^ b;
            zero = (temp_result == 32'b0);
            carry = 1'b0;
            negative = (temp_result[31] == 1'b1);
            overflow = 1'b0;
            flag = 1'b0;
        end

        6'b100111: begin 
            temp_result = ~(a | b);
            zero = (temp_result == 32'b0);
            carry = 1'b0;
            negative = (temp_result[31] == 1'b1);
            overflow = 1'b0;
            flag = 1'b0;
        end

        6'b101010: begin 
            temp_result = {{31{1'b0}}, (a < b)};
            zero = (temp_result == 32'b0);
            carry = 1'b0;
            negative = (temp_result[31] == 1'b1);
            overflow = 1'b0;
            flag = 1'b1;
        end

        6'b101011: begin 
            temp_result = {{31{1'b0}}, (a < b)};
            zero = (temp_result == 32'b0);
            carry = 1'b0;
            negative = (temp_result[31] == 1'b1);
            overflow = 1'b0;
            flag = 1'b1;
        end

        6'b000000: begin 
            temp_result = a << b;
            zero = (temp_result == 32'b0);
            carry = 1'b0;
            negative = (temp_result[31] == 1'b1);
            overflow = 1'b0;
            flag = 1'b0;
        end

        6'b000010: begin 
            temp_result = a >> b;
            zero = (temp_result == 32'b0);
            carry = 1'b0;
            negative = (temp_result[31] == 1'b1);
            overflow = 1'b0;
            flag = 1'b0;
        end

        6'b000011: begin 
            temp_result = $signed(a) >>> b;
            zero = (temp_result == 32'b0);
            carry = 1'b0;
            negative = (temp_result[31] == 1'b1);
            overflow = 1'b0;
            flag = 1'b0;
        end

        6'b000100: begin 
            temp_result = a << b;
            zero = (temp_result == 32'b0);
            carry = 1'b0;
            negative = (temp_result[31] == 1'b1);
            overflow = 1'b0;
            flag = 1'b0;
        end

        6'b000110: begin 
            temp_result = a >> b;
            zero = (temp_result == 32'b0);
            carry = 1'b0;
            negative = (temp_result[31] == 1'b1);
            overflow = 1'b0;
            flag = 1'b0;
        end

        6'b000111: begin 
            temp_result = $signed(a) >>> b;
            zero = (temp_result == 32'b0);
            carry = 1'b0;
            negative = (temp_result[31] == 1'b1);
            overflow = 1'b0;
            flag = 1'b0;
        end

        6'b001111: begin 
            temp_result = {b, 16'b0};
            zero = (temp_result == 32'b0);
            carry = 1'b0;
            negative = (temp_result[31] == 1'b1);
            overflow = 1'b0;
            flag = 1'b0;
        end

        default: begin
            temp_result = 32'b0;
            zero = 1'b0;
            carry = 1'b0;
            negative = 1'b0;
            overflow = 1'b0;
            flag = 1'b0;
        end
endcase

end // Auto-repaired
always @(posedge clk) begin
    r <= temp_result;
end
endmodule
